async (page) => {
  // 1. Open inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(800);
  // 2. Click the item slot (slot 0 = Bronze Axe)
  await page.evaluate((idx) => {
    const slots = document.querySelectorAll('.item-slot');
    if (slots[idx]) slots[idx].click();
  }, 0);
  await page.waitForTimeout(800);
  // 3. Click the equip button in the popup
  await page.evaluate(() => {
    const btn = document.querySelector('.action-equip');
    if (btn) btn.click();
  });
  await page.waitForTimeout(500);
  // 4. Close inventory panel
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(500);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return 'Equipped Bronze Axe';
}

async (page) => {
  // Click the door at the bottom of the building to exit
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 700, y: 575 });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      player_position: gs.player_position,
      player_stats: gs.player_stats,
      inventory: gs.inventory,
      nearby_entities: gs.nearby_entities.slice(0, 10).map(e => ({
