async (page) => {
  // Keep walking toward Village Girl - click upper-left repeatedly
  for (let i = 0; i < 3; i++) {
    await page.evaluate(() => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: 100, clientY: 120, bubbles: true }));
    });
    await page.waitForTimeout(3000);
    const state = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const vg = (gs.nearby_entities || []).find(e => e.name === 'Village Girl');
      return { pos: gs.player_position, vg_dist: vg?.distance, vg_cx: vg?.click_x, vg_cy: vg?.click_y };
