    return JSON.stringify({ pos: gs.player_position, vg_dist: vg?.distance, vg_cx: vg?.click_x });
  });
  return final;
}

async (page) => {
  // Walk directly toward Village Girl using tile math
  for (let i = 0; i < 5; i++) {
    await page.evaluate(() => {
      const gs = window.__latestGameState;
      const pp = gs.player_position;
      const vg = (gs.nearby_entities || []).find(e => e.name === 'Village Girl');
      if (!vg) return;
      const TILE = 48;
      const dx = vg.x - pp.x, dy = vg.y - pp.y;
      // Clamp to reachable canvas area
      const cx = Math.min(1150, Math.max(80, 640 + dx * TILE));
      const cy = Math.min(680, Math.max(50, 360 + dy * TILE));
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: cx, clientY: cy, bubbles: true }));
    });
    await page.waitForTimeout(3000);
    const dist = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return (gs.nearby_entities || []).find(e => e.name === 'Village Girl')?.distance;
    });
    if (dist <= 3) break;
  }

  const final = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const vg = (gs.nearby_entities || []).find(e => e.name === 'Village Girl');
    return JSON.stringify({ pos: gs.player_position, vg_dist: vg?.distance, vg_cx: vg?.click_x });
  });
  return final;
}

