async (page) => {
  // Walk toward Forester NPC
  for (let i = 0; i < 10; i++) {
    await page.evaluate(() => {
      const gs = window.__latestGameState;
      const pp = gs.player_position;
      const forester = (gs.nearby_entities || []).find(e => e.name === 'Forester');
      if (!forester) return;
      const TILE = 48;
      const dx = forester.x - pp.x, dy = forester.y - pp.y;
      const cx = Math.min(1150, Math.max(80, 640 + dx * TILE));
      const cy = Math.min(680, Math.max(50, 360 + dy * TILE));
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: cx, clientY: cy, bubbles: true }));
    });
    await page.waitForTimeout(3000);

    const state = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const forester = (gs.nearby_entities || []).find(e => e.name === 'Forester');
      return { pos: gs.player_position, f_dist: forester?.distance, hp: gs.player_stats.hp };
    });

    if (state.f_dist <= 3) return `Reached Forester! dist=${state.f_dist}`;
    if (state.hp < 50) return `Low HP: ${state.hp}`;
  }

  const final = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const forester = (gs.nearby_entities || []).find(e => e.name === 'Forester');
    return JSON.stringify({ pos: gs.player_position, f_dist: forester?.distance });
  });
  return final;
}

