async (page) => {
  // Walk toward Forester at ~(216, 114) from (191, 159)
  // Need to go +25 east and -45 north
  for (let i = 0; i < 8; i++) {
    await page.evaluate(() => {
      const gs = window.__latestGameState;
      const pp = gs.player_position;
      // Target: Forester at ~(216, 114)
      const targetX = 216, targetY = 114;
      const TILE = 48;
