async (page) => {
  let kills = 0;
  const startLevel = await page.evaluate(() => window.__latestGameState.player_stats.level);

  for (let i = 0; i < 15; i++) {
    // Atomic attack - read state and click in same eval
    const result = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const pp = gs.player_position;
      // Prefer Rats first (easy), then Batterfies
      const mob = (gs.nearby_entities || []).find(e => e.type === 3 && e.name === 'Rat' && e.distance <= 10)
               || (gs.nearby_entities || []).find(e => e.type === 3 && e.distance <= 8);
      if (!mob) return null;
      const TILE = 48;
      const cx = 640 + (mob.x - pp.x) * TILE;
      const cy = 360 + (mob.y - pp.y) * TILE;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: cx, clientY: cy, bubbles: true }));
      return { name: mob.name, dist: mob.distance };
    });

    if (!result) {
      // No mob - wander east
      await page.evaluate(() => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: 900, clientY: 360, bubbles: true }));
      });
      await page.waitForTimeout(3000);
      continue;
    }

    await page.waitForTimeout(result.name === 'Rat' ? 4000 : 7000);

    const st = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return { level: gs.player_stats.level, hp: gs.player_stats.hp, max_hp: gs.player_stats.max_hp };
    });

    kills++;

    // Heal if below 40%
    if (st.hp < st.max_hp * 0.4) {
      await page.evaluate(() => {
        // Try to eat food
        const inv = window.game.menu.getInventory();
        const edible = (window.__latestGameState.inventory || []).find(s => s.edible);
        if (edible) window.game.menu.getInventory().selectEdible(edible.slot);
        // Walk south to escape combat
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: 640, clientY: 560, bubbles: true }));
      });
      await page.waitForTimeout(8000);
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const gs = await page.evaluate(() => window.__latestGameState);
  return { kills, startLevel, endLevel: gs.player_stats.level, hp: gs.player_stats.hp, max_hp: gs.player_stats.max_hp, pos: gs.player_position };
}

