async (page) => {
  // Walk toward Forester
  for (let i = 0; i < 5; i++) {
    await page.evaluate(() => {
      const gs = window.__latestGameState;
      const pp = gs.player_position;
      const forester = (gs.nearby_entities || []).find(e => e.name === 'Forester');
      if (!forester) return;
      const TILE = 48;
      const dx = forester.x - pp.x, dy = forester.y - pp.y;
      const dist = Math.sqrt(dx*dx + dy*dy);
      const scale = Math.min(300, dist * TILE);
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {
        clientX: 640 + (dx/dist) * scale,
        clientY: 360 + (dy/dist) * scale, bubbles: true
      }));
    });
    await page.waitForTimeout(3000);
    const dist = await page.evaluate(() => {
      const f = (window.__latestGameState.nearby_entities || []).find(e => e.name === 'Forester');
      return f ? f.distance : 999;
    });
    if (dist <= 2) break;
  }

  // Click Forester and go through dialogue
  const clickF = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    const pp = gs.player_position;
    const f = (gs.nearby_entities || []).find(e => e.name === 'Forester');
    if (!f) return false;
    const TILE = 48;
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {
      clientX: 640 + (f.x - pp.x) * TILE,
      clientY: 360 + (f.y - pp.y) * TILE, bubbles: true
    }));
    return true;
  });

  for (let i = 0; i < 10; i++) {
    await clickF();
    await page.waitForTimeout(1200);
  }

  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) btn.click();
  });
  await page.waitForTimeout(1500);

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });

  const questState = await page.evaluate(() => {
    const p = window.game.player;
    const q = p.quests ? p.quests['foresting'] : null;
    return q ? { stage: q.stage, stageCount: q.stageCount } : null;
  });
  return { questState, pos: (await page.evaluate(() => window.__latestGameState)).player_position };
}

async (page) => {
  let chopCount = 0, resourceCount = 0, killCount = 0;

  for (let i = 0; i < 30; i++) {
    const action = await page.evaluate(() => {
      const gs = window.__latestGameState;
      const pp = gs.player_position;
      const TILE = 48;

      // Priority: Kill mobs if nearby, then chop Oaks, then collect resources
      const mob = (gs.nearby_entities || []).find(e => e.type === 3 && e.distance <= 6);
      const oak = (gs.nearby_entities || []).find(e => e.type === 10 && e.name === 'Oak' && e.distance <= 8);
      const resource = (gs.nearby_entities || []).find(e => e.type === 12 && e.distance <= 8);

      const target = mob || oak || resource;
      if (!target) return null;

      const dx = target.x - pp.x, dy = target.y - pp.y;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {
        clientX: 640 + dx * TILE, clientY: 360 + dy * TILE, bubbles: true
      }));
      return { type: target.type, name: target.name };
    });

    if (!action) {
      // Wander to find more resources
      await page.evaluate(() => {
        const x = 640 + (Math.random() - 0.5) * 500;
        const y = 360 + (Math.random() - 0.5) * 300;
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      });
      await page.waitForTimeout(3000);
      continue;
    }

    // Wait based on action type
    if (action.type === 3) { await page.waitForTimeout(8000); killCount++; }
    else if (action.type === 10) { await page.waitForTimeout(6000); chopCount++; }
    else { await page.waitForTimeout(4000); resourceCount++; }

    // Check HP
    const st = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return { hp: gs.player_stats.hp, max_hp: gs.player_stats.max_hp };
    });
    if (st.hp < st.max_hp * 0.3) {
      await page.evaluate(() => document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: 640, clientY: 600, bubbles: true })));
      await page.waitForTimeout(12000);
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const gs = await page.evaluate(() => window.__latestGameState);
  const inv = gs.inventory.map(i => `${i.name}x${i.count}`);
  return { chopCount, resourceCount, killCount, level: gs.player_stats.level, hp: `${gs.player_stats.hp}/${gs.player_stats.max_hp}`, inv, pos: gs.player_position };
}

