async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  let kills = 0;

  for (let round = 0; round < 15; round++) {
    // Find nearest rat
    const mob = await page.evaluate(() => {
      const g = window.game, p = g.player;
      const rat = Object.values(g.entities?.entities || {})
        .filter(e => e && e !== p && e.name === 'Rat' && e.hp > 0)
        .sort((a, b) => (Math.abs(a.gridX-p.gridX)+Math.abs(a.gridY-p.gridY)) - (Math.abs(b.gridX-p.gridX)+Math.abs(b.gridY-p.gridY)))
        [0];
      return rat ? { cx: Math.round(640+(rat.gridX-p.gridX)*48), cy: Math.round(360+(rat.gridY-p.gridY)*48), dist: Math.abs(rat.gridX-p.gridX)+Math.abs(rat.gridY-p.gridY) } : null;
    });

    if (!mob) {
      await page.waitForTimeout(3000);
      continue;
    }

    // Approach if far
    if (mob.dist > 10) {
      const edgeCx = Math.max(100, Math.min(1180, mob.cx));
      const edgeCy = Math.max(100, Math.min(620, mob.cy));
      await click(edgeCx, edgeCy);
      await page.waitForTimeout(3000);
    }

    await click(mob.cx, mob.cy);
    await page.waitForTimeout(5000); // Wait for kill
    kills++;

    // Check if subStage changed
    const subStage = await page.evaluate(() => {
      return window.game.player?.quests?.foresting?.subStage;
    });

    if (subStage !== 3) {
      return `SubStage changed to ${subStage} after ${kills} kills!`;
    }
  }

  const finalSubStage = await page.evaluate(() => window.game.player?.quests?.foresting?.subStage);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return `Killed ${kills} rats, subStage still: ${finalSubStage}`;
}

