    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Attack the rat at (784, 264)
  await click(784, 264);
  await page.waitForTimeout(6000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const gs = JSON.parse(state);
  const pos = gs.player_position;
  const hp = gs.player_stats;

  // Check for any XP gain
  const drops = gs.nearby_entities?.filter(e => e.type === 4);

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos, hp: `${hp.hp}/${hp.max_hp}`, level: hp.level, xp: hp.experience, drops });
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  let kills = 0;
  let totalXp = 0;

  // Grind loop - kill 5 rats
  for (let i = 0; i < 8; i++) {
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const gs = JSON.parse(state);
    const rat = gs.nearby_entities?.find(e => e.name === 'Rat' && e.type === 3 && e.hp > 0);

    if (rat && rat.on_screen) {
      await click(rat.click_x, rat.click_y);
      await page.waitForTimeout(6000);
      kills++;
    } else if (rat) {
      // Rat off screen, walk toward it
      const dx = Math.sign(rat.click_x - 640) * 200;
      const dy = Math.sign(rat.click_y - 360) * 150;
      await click(640 + dx, 360 + dy);
      await page.waitForTimeout(3000);
    } else {
      // No rat, walk east to find one
      await click(900, 360);
      await page.waitForTimeout(3000);
    }

    // Loot any drops
    const drops = (await page.evaluate(() => JSON.stringify(window.__latestGameState))).includes('"type":4');
    if (drops) {
      const gs2 = JSON.parse(await page.evaluate(() => JSON.stringify(window.__latestGameState)));
      const drop = gs2.nearby_entities?.find(e => e.type === 4 && e.on_screen);
      if (drop) {
        await click(drop.click_x, drop.click_y);
        await page.waitForTimeout(1000);
      }
    }
  }

  const finalState = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const fs = JSON.parse(finalState);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos: fs.player_position, hp: `${fs.player_stats.hp}/${fs.player_stats.max_hp}`, level: fs.player_stats.level, kills });
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  let kills = 0;

  for (let i = 0; i < 15; i++) {
    const gs = JSON.parse(await page.evaluate(() => JSON.stringify(window.__latestGameState)));
    const hp = gs.player_stats;

    // Heal if HP < 50%
    if (hp.hp < hp.max_hp * 0.5) {
      // Back away and wait
      await click(640 - 4*48, 360);
      await page.waitForTimeout(4000);
      continue;
    }

    // Loot first
    const drop = gs.nearby_entities?.find(e => e.type === 4 && e.on_screen);
    if (drop) {
      await click(drop.click_x, drop.click_y);
      await page.waitForTimeout(1000);
      continue;
    }

    // Attack rat
    const rat = gs.nearby_entities?.find(e => e.name === 'Rat' && e.type === 3 && e.hp > 0 && e.on_screen);
    if (rat) {
      await click(rat.click_x, rat.click_y);
      await page.waitForTimeout(6000);
      kills++;
    } else {
      // Move to find rats
      await click(900 + Math.random()*100, 300 + Math.random()*100);
      await page.waitForTimeout(3000);
    }
  }

  const fs = JSON.parse(await page.evaluate(() => JSON.stringify(window.__latestGameState)));
  const inv = fs.inventory?.map(i => i.name);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos: fs.player_position, hp: `${fs.player_stats.hp}/${fs.player_stats.max_hp}`, level: fs.player_stats.level, kills, inventory: inv });
}

