    const gs = window.__latestGameState;
    const mobs = (gs?.nearby_entities || []).filter(e => e.type === 3 && e.hp > 0 && e.on_screen && e.name === 'Rat');
    const items = (gs?.nearby_entities || []).filter(e => e.type === 4);
    return { pos: gs?.player_position, hp: gs?.player_stats?.hp, level: gs?.player_stats?.level, xp: gs?.player_stats?.experience, rats: mobs.slice(0, 3).map(m => ({cx: m.click_x, cy: m.click_y, dist: m.distance})), drops: items.slice(0, 3).map(i => ({name: i.name, cx: i.click_x, cy: i.click_y})) };
  });

  // Kill 3 more rats
  for (let i = 0; i < 3; i++) {
    let s = await getState();
    // Check drops first
    if (s.drops.length > 0) {
      const drop = s.drops[0];
      console.log('picking up drop:', drop.name);
      await click(drop.cx, drop.cy);
      s = await getState();
