async (page) => {
  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, {x, y});
    await page.waitForTimeout(4500);
  };

  const getState = () => page.evaluate(() => {
    const gs = window.__latestGameState;
    const npcs = (gs?.nearby_entities || []).filter(e => e.type === 1).map(e => ({name: e.name, x: e.x, y: e.y, dist: e.distance, quest_npc: e.quest_npc, cx: e.click_x, cy: e.click_y}));
    return { pos: gs?.player_position, hp: gs?.player_stats?.hp, level: gs?.player_stats?.level, forester: npcs.find(n=>n.name==='Forester') };
  });

  // From (195, 150) → Forester (216, 114): need NE navigation
  // Path: go east first along y=160 road to x=216, then straight north
  // The road east (Snek bridge) is at y≈160. Let me go south then east then north

  // Try: click far NE to reach Forester area
  for (let i = 0; i < 10; i++) {
    let s = await getState();
    if (!s.pos) break;

    const forester = s.forester;
    if (forester && forester.cx > 50 && forester.cx < 1230 && forester.cy > 50 && forester.cy < 630) {
      console.log('Forester on screen! dist:', forester.dist, 'at canvas:', forester.cx, forester.cy);
      await click(forester.cx, forester.cy);
      break;
    }

    // Navigate toward Forester (216, 114) from current position
    const targetX = 216, targetY = 114;
    const dx = targetX - s.pos.x;
    const dy = targetY - s.pos.y;

    // Calculate canvas click (max 5 tiles per step, cap y at 150 min)
    const stepX = Math.max(-5, Math.min(5, dx));
    const stepY = Math.max(-5, Math.min(5, dy));
    const cx = 640 + stepX * 48;
    const cy = Math.max(130, 360 + stepY * 48);

    console.log(`step ${i+1}: pos=(${s.pos.x},${s.pos.y}), click=(${cx},${cy}), dx=${dx}, dy=${dy}`);
    await click(cx, cy);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  const final = await getState();
  return JSON.stringify(final);
}

